const root = $json;

// ---------- helpers ----------
function isObject(v) {
  return v && typeof v === "object" && !Array.isArray(v);
}

function asNumber(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function hasValue(v) {
  return v !== undefined && v !== null && v !== "";
}

function findFirstByKeys(node, keys) {
  if (Array.isArray(node)) {
    for (const item of node) {
      const found = findFirstByKeys(item, keys);
      if (found !== undefined) return found;
    }
    return undefined;
  }
  if (!isObject(node)) return undefined;

  for (const k of Object.keys(node)) {
    if (keys.includes(k) && node[k] !== undefined && node[k] !== null && node[k] !== "") {
      return node[k];
    }
  }

  for (const k of Object.keys(node)) {
    const found = findFirstByKeys(node[k], keys);
    if (found !== undefined) return found;
  }

  return undefined;
}

function findArrayByLikelyKeys(node, keys) {
  const found = findFirstByKeys(node, keys);
  return Array.isArray(found) ? found : [];
}

function gatherAllStrings(node, out = []) {
  if (typeof node === "string") out.push(node);
  else if (Array.isArray(node)) {
    for (const x of node) gatherAllStrings(x, out);
  } else if (isObject(node)) {
    for (const k of Object.keys(node)) gatherAllStrings(node[k], out);
  }
  return out;
}

function normalizeBool(v, fallback = false) {
  if (typeof v === "boolean") return v;
  if (typeof v === "number") return v !== 0;
  if (typeof v === "string") {
    const s = v.trim().toLowerCase();
    if (["true", "yes", "1", "found", "completed", "success"].includes(s)) return true;
    if (["false", "no", "0", "missing", "not_found", "failed"].includes(s)) return false;
  }
  return fallback;
}

// ---------- raw text ----------
const allStrings = gatherAllStrings(root, []);
const combinedText = allStrings.join(" | ");

// ---------- states ----------
let states = findArrayByLikelyKeys(root, ["states", "state_history", "timeline", "transitions"]);
states = states.filter(x => isObject(x));

// ---------- derive patient found ----------
const patientFound =
  normalizeBool(findFirstByKeys(root, ["patient_found", "patient_detected", "target_found"]), false) ||
  states.some(s => String(s.to || "").toUpperCase() === "READ_BED_LABEL") ||
  states.some(s => String(s.to || "").toUpperCase() === "FIND_MONITOR") ||
  states.some(s => String(s.to || "").toUpperCase() === "SAVE_RESULTS") ||
  /patient found|patient found and approached/i.test(combinedText);

// ---------- derive clinical check done ----------
const clinicalCheckDone =
  normalizeBool(findFirstByKeys(root, ["clinical_check_done", "monitor_found", "vitals_monitor_found", "screen_found"]), false) ||
  states.some(s => String(s.to || "").toUpperCase() === "SAVE_RESULTS") ||
  /monitor snapshot saved|results saved/i.test(combinedText);

// ---------- mission complete ----------
const missionComplete =
  normalizeBool(findFirstByKeys(root, ["mission_complete", "completed", "success"]), false) ||
  clinicalCheckDone ||
  /review required|completed|success|done/i.test(combinedText);

// ---------- direct fields ----------
const urgencyLevel = findFirstByKeys(root, ["urgency_level", "urgency"]) ?? null;
const clinicalNote = findFirstByKeys(root, ["clinical_note", "summary_note", "note"]) ?? null;
const statusLight = findFirstByKeys(root, ["status_light"]) ?? null;
const missionStatusText = findFirstByKeys(root, ["mission_status_text", "mission_status", "status_text"]) ?? null;

// ---------- vitals ----------
const hr = asNumber(findFirstByKeys(root, ["heart_rate_bpm", "hr", "heart_rate"]));
const spo2 = asNumber(findFirstByKeys(root, ["spo2_percent", "spo2"]));
const temp = asNumber(findFirstByKeys(root, [
  "temperature_c",
  "face_temperature_c",
  "forehead_temperature_c",
  "chest_temperature_c"
]));
const rr = asNumber(findFirstByKeys(root, [
  "respiration_rpm",
  "respiration_rate_bpm",
  "respiratory_rate",
  "rr"
]));

const vitalsAvailable =
  hasValue(hr) || hasValue(spo2) || hasValue(temp) || hasValue(rr) ||
  hasValue(urgencyLevel) || hasValue(clinicalNote);

// ---------- emergency ----------
const emergencyCase =
  normalizeBool(findFirstByKeys(root, ["emergency_case", "emergency", "is_emergency"]), false) ||
  String(urgencyLevel || "").toLowerCase() === "high" ||
  String(statusLight || "").toLowerCase() === "red" ||
  /urgent human review|unstable patient|emergency/i.test(combinedText);

// ---------- risk signals ----------
const riskSignals = [];
if (hasValue(hr) && hr >= 120) riskSignals.push("tachycardia");
if (hasValue(spo2) && spo2 < 90) riskSignals.push("hypoxemia");
if (hasValue(temp) && temp >= 38.5) riskSignals.push("fever");
if (hasValue(rr) && rr > 24) riskSignals.push("high respiratory rate");
if (String(urgencyLevel || "").toLowerCase() === "high") riskSignals.push("high urgency level");
if (String(statusLight || "").toLowerCase() === "red") riskSignals.push("critical status light");
if (/urgent human review/i.test(combinedText)) riskSignals.push("urgent human review recommended");
if (/unstable patient/i.test(combinedText)) riskSignals.push("clinical instability noted");

// ---------- risk ----------
let preliminaryRisk = "Low";
if (emergencyCase || riskSignals.includes("hypoxemia") || riskSignals.length >= 3) {
  preliminaryRisk = "Critical";
} else if (riskSignals.length === 2) {
  preliminaryRisk = "High";
} else if (riskSignals.length === 1) {
  preliminaryRisk = "Moderate";
}

// ---------- explainability ----------
const explainabilityHints = [];
if (patientFound) explainabilityHints.push("Patient was found and approached.");
if (clinicalCheckDone) explainabilityHints.push("Clinical check reached result-saving stage.");
if (hasValue(hr)) explainabilityHints.push(`Heart rate: ${hr} bpm.`);
if (hasValue(spo2)) explainabilityHints.push(`SpO2: ${spo2}%.`);
if (hasValue(temp)) explainabilityHints.push(`Temperature: ${temp} °C.`);
if (hasValue(rr)) explainabilityHints.push(`Respiration rate: ${rr} rpm.`);
if (urgencyLevel) explainabilityHints.push(`Urgency level: ${urgencyLevel}.`);
if (clinicalNote) explainabilityHints.push(String(clinicalNote));
if (missionStatusText) explainabilityHints.push(`Mission status: ${missionStatusText}.`);

return [
  {
    json: {
      available: true,
      patient_found: patientFound,
      clinical_check_done: clinicalCheckDone,
      vitals_available: vitalsAvailable,
      mission_complete: missionComplete,
      emergency_case: emergencyCase,
      urgency_level: urgencyLevel,
      clinical_note: clinicalNote,
      status_light: statusLight,
      mission_status_text: missionStatusText,
      vitals: {
        heart_rate_bpm: hr,
        spo2_percent: spo2,
        temperature_c: temp,
        respiration_rpm: rr
      },
      risk_signals: riskSignals,
      preliminary_risk: preliminaryRisk,
      explainability_hints: explainabilityHints,
      validation: {
        patient_not_found: !patientFound,
        clinical_check_missing: !clinicalCheckDone,
        vitals_missing: !vitalsAvailable,
        mission_incomplete: !missionComplete
      },
      raw_states: states
    }
  }
];

let raw = $json;

// Sometimes the model output arrives inside a `text` field as a JSON string
if (typeof raw.text === 'string') {
  try {
    raw = JSON.parse(raw.text);
  } catch (e) {
    const match = raw.text.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        raw = JSON.parse(match[0]);
      } catch {
        raw = { raw_text: raw.text };
      }
    } else {
      raw = { raw_text: raw.text };
    }
  }
}

// Helper
function asArray(v) {
  return Array.isArray(v) ? v : [];
}

function asRisk(v) {
  const allowed = ["Low", "Moderate", "High", "Critical"];
  return allowed.includes(v) ? v : "Unknown";
}

const finalJson = {
  available: raw.available ?? true,
  assessment:
    typeof raw.assessment === "string"
      ? raw.assessment
      : raw.clinical_note
      ?? raw.summary
      ?? "No assessment available.",
  risk_level:
    asRisk(raw.risk_level)
      || (raw.assessment?.urgency_level === "high" ? "High" : "Unknown"),
  recommendation:
    typeof raw.recommendation === "string"
      ? raw.recommendation
      : raw.human_review_recommended
      ? "Immediate human assessment required."
      : "No recommendation available.",
  confidence:
    typeof raw.confidence === "number"
      ? raw.confidence
      : 0.75,
  summary:
    typeof raw.summary === "string"
      ? raw.summary
      : typeof raw.mission_status_text === "string"
      ? raw.mission_status_text
      : "No summary available.",
  explainability:
    asArray(raw.explainability).length
      ? raw.explainability
      : [
          raw.clinical_note,
          raw.assessment?.urgency_level ? `Urgency level: ${raw.assessment.urgency_level}` : null,
          raw.vitals?.spo2_percent ? `SpO2: ${raw.vitals.spo2_percent}%` : null,
          raw.vitals?.heart_rate_bpm ? `Heart rate: ${raw.vitals.heart_rate_bpm} bpm` : null,
          raw.vitals?.temperature_c ? `Temperature: ${raw.vitals.temperature_c} °C` : null
        ].filter(Boolean),
  alerts:
    asArray(raw.alerts).length
      ? raw.alerts
      : [
          raw.assessment?.urgency_level === "high" ? "High urgency patient condition" : null,
          raw.human_review_recommended ? "Human review recommended" : null,
          raw.status_light === "red" ? "Critical status light triggered" : null
        ].filter(Boolean)
};

const jsonString = JSON.stringify(finalJson, null, 2);

return [
  {
    binary: {
      data: {
        data: Buffer.from(jsonString).toString("base64"),
        mimeType: "application/json",
        fileName: "ai_inspection.json"
      }
    }
  }
];
